import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { defineTool } from "eve/tools";
import { z } from "zod";

/** Deterministic stub so evals never need a weather API. */
export default defineTool({
  description: "Get the current weather for a city (stubbed for demos).",
  inputSchema: z.object({
    city: z.string().min(1),
  }),
  async execute({ city }) {
    return {
      city,
      condition: "Sunny",
      temperatureF: 72,
      note: "Stubbed result for eval demos.",
    };
  },
});

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

/** Exists so evals can assert t.parked() + pending tool status. */
export default defineTool({
  description: "Issue a refund. Always requires human approval first.",
  inputSchema: z.object({
    chargeId: z.string().min(1),
    amountCents: z.number().int().positive(),
  }),
  approval: always(),
  async execute({ chargeId, amountCents }) {
    return { status: "refunded", chargeId, amountCents };
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Gate: the run completed successfully (t.succeeded).",
  async test(t) {
    await t.send("Say hi in three words.");
    t.succeeded();
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Gate: the right tool ran with matching input (t.calledTool).",
  async test(t) {
    await t.send("What is the weather in Brooklyn? Use get_weather.");
    t.succeeded();
    t.calledTool("get_weather", {
      input: { city: /brooklyn/i },
    });
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Gate: approval parks the session (t.parked + pending tool).",
  async test(t) {
    await t.send(
      "Issue a refund for charge ch_eval_1 amounting to 1000 cents now."
    );
    t.parked();
    t.calledTool("issue_refund", { status: "pending", count: 1 });
  },
});

import { defineEval } from "eve/evals";
import { includes, satisfies } from "eve/evals/expect";

export default defineEval({
  description: "Gate + soft: t.check with includes and satisfies.",
  async test(t) {
    await t.send("What is the weather in Brooklyn? Use get_weather.");
    t.succeeded();
    t.check(t.reply, includes(/sunny/i));
    t.check(
      t.reply,
      satisfies(
        (reply: string) => reply.length < 2000,
        "reply is under 2000 chars"
      )
    ).soft();
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description:
    "Soft: LLM-as-judge grades the reply (tracked, not a hard fail).",
  async test(t) {
    await t.send("What is the weather in Brooklyn? Use get_weather.");
    t.succeeded();
    t.calledTool("get_weather");
    // Soft by default — appears in reports; use --strict to fail on threshold.
    t.judge.autoevals.closedQA("Mentions sunny or clear weather for Brooklyn");
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 1,
  timeoutMs: 120_000,
  // Optional judge defaults for soft LLM grading (see judge.eval.ts).
  judge: { model: "openai/gpt-5.4-mini" },
});
